import csv, json, textwrap
from pathlib import Path
from datetime import datetime

ROOT=Path('Module10_Dry_Run')
APP=ROOT/'standalone-course-mvp'
OUT=ROOT/'_module10_dryrun_outputs'
for d in ['data','audio','media','reports']:
    (OUT/d).mkdir(parents=True, exist_ok=True)
(APP/'src/data').mkdir(parents=True, exist_ok=True)
source_map=json.load(open(OUT/'source_map/source_objective_map.json',encoding='utf-8'))
SOURCE=source_map['source_authority']
objectives=source_map['objectives']
activity_by_obj={o['objective_number']:[a['name'] for a in o['required_activities']] for o in objectives}

# Schema, content, activities
schema={
  '$schema':'https://json-schema.org/draft/2020-12/schema','title':'Module10SourceFirstContent','type':'object',
  'required':['module_id','title','source_authority','objectives','total_weighted_minutes'],
  'properties':{'module_id':{'const':'M10'},'title':{'const':'NATP Module 10: Vital Signs'},'total_weighted_minutes':{'const':180},'objectives':{'type':'array','minItems':16,'maxItems':16}}
}
content={'module_id':'M10','title':'NATP Module 10: Vital Signs','source_authority':SOURCE,'purpose':source_map['purpose'],'total_weighted_minutes':180,'clinical_boundary':'Six source-recommended clinical hours are deferred to in-person/evaluator-supported work and are not online credit.','objectives':objectives}
activities={'module_id':'M10','source_authority':SOURCE,'objectives':[]}
for o in objectives:
    acts=[]
    for idx,name in enumerate(activity_by_obj[o['objective_number']],1):
        acts.append({'activity_id':f"M10-O{o['objective_number']:02d}-A{idx:02d}",'name':name,'objective_number':o['objective_number'],'source_reference':o['source_reference'],'mobile_pattern':'tap-card / choose / sort / short-response as appropriate','completion_event':f"activity_complete:M10:O{o['objective_number']:02d}:A{idx:02d}",'accessibility_notes':'Keyboard reachable, text alternative required for visuals, no autoplay audio.','media_requirements':o['image_requirements'],'narration_requirements':o['narration_requirements'],'sfx_requirements':o['sfx_requirements'],'compliance_boundary':'Source-traced theory practice only; no online hands-on competency validation; no PHI.'})
    activities['objectives'].append({'objective_number':o['objective_number'],'weighted_minutes':o['weighted_minutes'],'activities':acts})

for rel,data in [('module10.schema.json',schema),('module10.content.json',content),('module10.activities.json',activities)]:
    (OUT/'data'/rel).write_text(json.dumps(data,indent=2,ensure_ascii=False),encoding='utf-8')
    (APP/'src/data'/rel).write_text(json.dumps(data,indent=2,ensure_ascii=False),encoding='utf-8')

# Build app-compatible courseContentV2 JSON
def card(o, lesson_id, card_id, card_type, title, body, challenge=None):
    loc=f"module.m10.lesson.{lesson_id.lower()}.card.{card_id.lower()}_{card_type}"
    return {'module_id':'M10','lesson_id':lesson_id,'card_id':card_id,'card_type':card_type,'app_location':loc,'app':{'route':f'/modules/m10/lesson/{lesson_id.lower().replace("l0","l") if lesson_id.startswith("L0") else lesson_id.lower()}','location':loc},'scene_title':title,'display_title':title,'media_prompt_placeholder':{'scene_title':title,'alt_text':f'Training visual: {title}. De-identified illustration; no PHI.'},'estimated_narration_seconds':45,'narration_script':body,'learning_goal':f"Objective {o['objective_number']}: {o['objective_title']}",'learner_facing_content':body,'why_it_matters':[f"This supports source Objective {o['objective_number']} and CNA observe-report-record responsibilities."],'cna_practice_example':'Use the source rule in a fictional, de-identified resident-care scenario and report abnormal findings to the licensed nurse when required.','key_terms':[{'term':t,'definition':f'Source terminology for Objective {o["objective_number"]}: {t}.'} for t in (o.get('terminology') or source_map['terminology'])[:3]],'transcript_text':body,'sme_review_flag':'Source-traced draft; SME review required before production.', 'internal_challenge': challenge}
lessons=[]
module_questions=[]
for o in objectives:
    n=o['objective_number']; lid=f'L{n:02d}'
    outline=' '.join(o['content_outline'])
    overview=f"This lesson covers Objective {n}: {o['objective_title']}. Weighted theory time: {o['weighted_minutes']} minutes. Source pages: {', '.join(map(str,o['source_pages']))}."
    delivery=f"Source-traced teaching outline: {outline}\n\nCNA boundary: observe, measure, record, and report according to facility policy and licensed-nurse direction. This dry run does not validate hands-on competency or claim clinical-hour credit."
    q={'id':f'M10-O{n:02d}-KC','app_location':f'module.m10.lesson.{lid.lower()}.challenge','prompt':f"In Objective {n}, what is the safest CNA boundary to remember?",'choices':[{'id':'A','label':'Treat the activity as online clinical competency validation.'},{'id':'B','label':'Use the source guidance for theory practice and report abnormal findings or complaints to the licensed nurse.'},{'id':'C','label':'Use old ContentV2 examples if the PDF is hard to read.'},{'id':'D','label':'Skip source references once the activity looks complete.'}], 'correct_id_internal':'B','rationale_internal':'The source supports theory instruction and CNA observe/report/record duties; clinical competency and abnormal findings remain licensed/evaluator-supported boundaries.','option_rationales_internal':{'A':'This would falsely claim online hands-on competency validation.','B':'This preserves source meaning and CNA scope.','C':'Old ContentV2 is not source authority.','D':'Every artifact must remain source-traced.'},'source_reference':o['source_reference']}
    lessons.append({'lesson_id':lid,'lesson_title':f"Objective {n}: {o['objective_title']}",'estimated_minutes':o['weighted_minutes'],'objective_number':n,'weighted_minutes':o['weighted_minutes'],'source_reference':o['source_reference'],'cards':[card(o,lid,'C01','overview',f'Objective {n} Overview',overview),card(o,lid,'C02','delivery',f'Objective {n} Source Teaching',delivery),card(o,lid,'C03','challenge',f'Objective {n} Practice Check',f"Practice applying Objective {n} using the source-traced content.",q),card(o,lid,'C04','debrief',f'Objective {n} Debrief',f"Review the safest source-traced response for Objective {n}.")]})
    module_questions.append({'id':f'M10-Q{n:02d}','prompt':f"Objective {n}: Which action best preserves CNA scope and source-traced practice?",'choices':q['choices'],'correct_id_internal':'B','source_reference':o['source_reference']})
course={'app_copy':{'dashboard':{'badge':'Module 10 Dry Run','title':'NATP Module 10: Vital Signs','summary':'Source-first dry run generated from the approved NATP Module 10 PDF.','theory_card':'180 minutes of source-traced theory content.','clinical_card':'6 clinical hours are source-recommended only and deferred; not online credit.','audit_card':'Source map, manifests, and validation report are generated for audit review.','compliance_notice':'No CDPH/TPRU approval, certificate production, online clinical credit, or online competency validation is claimed.'},'module0':{'eyebrow':'Module 10 only','title':'NATP Module 10: Vital Signs','intro':'This dry run contains Module 10 only; no orientation or full-course routing is active.','acknowledgements':[{'key':'identity','text':'I understand this is a Module 10 dry run.'},{'key':'onlineCap','text':'I understand clinical time is not online credit.'},{'key':'clinicalBoundary','text':'I understand hands-on competency is deferred to in-person/evaluator-supported work.'}]},'moduleAssessment':{'title':'Module 10 Knowledge Check','summary':'Source-traced objective checks for Module 10 only.'},'final':{'title':'Module 10 Review Check','summary':'Dry-run review only; no production final exam claim.','no_key_notice':'Answer keys are internal-only and not shown as learner content.','pass_title':'Module 10 Review Complete','pass_body':'Dry-run only; no certificate or approval claim.','fail_title':'Review Module 10 Objectives'},'certificate':{'checklist_title':'Certificate Disabled for Dry Run','intro':'Certificate production is not part of this Module 10 dry run.','locked_body':'Certificate remains locked and non-production.','ready_body':'Dry-run complete does not issue a production certificate.','restriction':'No clinical-hour credit, CDPH/TPRU approval, or online hands-on competency validation is claimed.','affidavit_text':'I confirm this is a non-production Module 10 dry run.'},'clinicalHub':{'eyebrow':'Clinical boundary','badge':'Deferred','title':'Clinical Support Deferred','warning':'Clinical practice is source-recommended only and not online credit.','documentation_title':'Documentation Support','documentation_warning':'Do not enter PHI. Use fictional, de-identified practice only.','scenarios':[{'title':'In-person clinical practice deferred','body':'Manual skills require evaluator-supported practice and are not validated online.','action':'Use as theory preparation only'}]}},'control_facts':{'theory_total_minutes':180,'source_authority':SOURCE},'clinical_support':{'units':[],'confidence_checks':[]},'modules':[{'module_id':'M10','module_title':'NATP Module 10: Vital Signs','short_title':'Vital Signs','estimated_minutes':180,'status':'ready','counts_toward_theory':True,'source_status_flag':'Generated from approved Module 10 PDF source map.','sme_review_flag':'SME review required before production.','compliance_review_flag':'Dry-run only; no approval/credit/certificate/competency claim.','learning_objectives':[o['exact_objective_statement'] for o in objectives],'lessons':lessons}], 'assessments':{'module_assessments':{'M10':{'title':'Module 10 Knowledge Check','pass_percent':80,'questions':module_questions}},'final_assessment':{'attempt_size':min(10,len(module_questions)),'pass_percent':80,'answer_key_policy':'Internal scoring only; answer keys are not displayed as learner-facing content.','remediation_map':{f'Objective {o["objective_number"]}':o['objective_title'] for o in objectives},'questions':module_questions[:10]}}}
(OUT/'data/content.generated.json').write_text(json.dumps(course,indent=2,ensure_ascii=False),encoding='utf-8')
(APP/'src/data/module10.generated.ts').write_text("import module10CourseContent from './module10.content.generated.json';\n\nexport const courseContentV2 = module10CourseContent;\n",encoding='utf-8')
(APP/'src/data/module10.content.generated.json').write_text(json.dumps(course,indent=2,ensure_ascii=False),encoding='utf-8')
# app adapter source
(APP/'src/data/contentV2.generated.ts').write_text("import module10CourseContent from './module10.content.generated.json';\n\nexport const courseContentV2 = module10CourseContent;\n",encoding='utf-8')

# Audio scripts and manifest
with (OUT/'audio/audio_scripts.csv').open('w',encoding='utf-8',newline='') as f:
    w=csv.DictWriter(f,fieldnames=['clip_id','type','objective_number','title','transcript','source_reference','voice_reference','generated_status','approval_status','final_path','review_note'])
    w.writeheader()
    for o in objectives:
        w.writerow({'clip_id':f'M10-O{o["objective_number"]:02d}-INTRO','type':'objective_intro','objective_number':o['objective_number'],'title':f'Objective {o["objective_number"]} intro','transcript':f"Objective {o['objective_number']}: {o['objective_title']}. This is source-traced theory instruction only.",'source_reference':o['source_reference'],'voice_reference':'C:/AI/Git/training/CI-ION/CI-ION_OASIS-E2_SOC/src/content/narration/Additional Narrations OASIS-E2/FINAL_REVIEW_EXPORT_GUIDANCE_001.wav','generated_status':'queued_not_generated','approval_status':'scripts_source_validated_generation_gated','final_path':'','review_note':'Generate only after explicit audio approval.'})
        for a in activity_by_obj[o['objective_number']]:
            w.writerow({'clip_id':f'M10-O{o["objective_number"]:02d}-{a.replace(" ","_").replace("/","")[:24]}','type':'activity_instruction','objective_number':o['objective_number'],'title':a,'transcript':f"Activity: {a}. Use the source guidance for Objective {o['objective_number']} and stay within CNA observe, report, and record boundaries.",'source_reference':o['source_reference'],'voice_reference':'C:/AI/Git/training/CI-ION/CI-ION_OASIS-E2_SOC/src/content/narration/Additional Narrations OASIS-E2/FINAL_REVIEW_EXPORT_GUIDANCE_001.wav','generated_status':'queued_not_generated','approval_status':'scripts_source_validated_generation_gated','final_path':'','review_note':'Generate only after explicit audio approval.'})
audio_manifest={'status':'scripts_only_no_audio_generated','qwen_model':'C:/AI/Qwen3-TTS-12Hz-1.7B-Base','voice_reference':'C:/AI/Git/training/CI-ION/CI-ION_OASIS-E2_SOC/src/content/narration/Additional Narrations OASIS-E2/FINAL_REVIEW_EXPORT_GUIDANCE_001.wav','clips':'See audio_scripts.csv','compliance':'No final speech audio generated in this run.'}
(OUT/'audio/audio_manifest.json').write_text(json.dumps(audio_manifest,indent=2),encoding='utf-8')
# SFX manifest
sfx_names=['regular pulse beat','irregular pulse beat','slow pulse beat','fast pulse beat','normal quiet breathing','labored breathing','shallow breathing','rapid breathing','slow breathing','stertorous/snoring-type breathing','apnea pause/silence','BP first/last sounds','cuff inflation','cuff deflation','thermometer beep','neutral room tone']
sfx={'status':'queued_no_sfx_assets_used','items':[{'name':n,'source_url_or_local_path':'','license':'queued_license_required_before_use','attribution_requirement':'TBD before use','commercial_use_status':'blocked_until_licensed_source_selected','final_asset_path':'','source_objective':'Module 10 relevant objective(s)','review_notes':'Do not use without complete license metadata.'} for n in sfx_names]}
(OUT/'audio/sfx_manifest.json').write_text(json.dumps(sfx,indent=2),encoding='utf-8')
# Images
categories=['vital signs dashboard','thermometer types','temperature route comparison','pulse site body map','circulatory pulse concept visual','respiration observation visual','abnormal breathing pattern visual','TPR sequence timeline','BP equipment labeling diagram','cuff placement coach','one-step/two-step BP procedure visuals','do-not-use-this-arm BP safety visuals','pain scale role play visual','charting mock forms','fictional resident room scenes']
img_items=[]
for i,c in enumerate(categories,1):
    img_items.append({'image_id':f'M10-IMG-{i:02d}','category':c,'prompt':f'Professional healthcare education illustration for NATP Module 10 Vital Signs: {c}; fictional de-identified training scene; mobile-readable; no facility logos; no readable patient records; no PHI.','negative_prompt':'PHI, real names, facility logos, readable charts, gore, exaggerated illness imagery, unsafe clinical action, certificate or approval claims','source_reference':SOURCE,'alt_text':f'Training visual for {c}; de-identified and source-traced.','final_path':'','review_status':'queued_prompt_only_not_generated'} )
(OUT/'media/image_manifest.json').write_text(json.dumps({'status':'prompt_queue_only_no_images_generated','items':img_items},indent=2),encoding='utf-8')
(OUT/'media/image_prompt_queue.json').write_text(json.dumps(img_items,indent=2),encoding='utf-8')
# Reports
(OUT/'reports/time_allotment_report.md').write_text('# Time Allotment Report\n\nTotal weighted theory minutes: 180. Assessment, clinical, certificate, and optional support minutes excluded.\n\n'+'\n'.join([f"- Objective {o['objective_number']}: {o['weighted_minutes']} minutes — {o['objective_title']}" for o in objectives])+'\n',encoding='utf-8')
(OUT/'reports/lessonplayer_review.md').write_text('# LessonPlayer Review\n\nDecision: preserve and reuse the existing `standalone-course-mvp/src/pages/LessonPlayerPage.tsx` MediaLessonPlayer-equivalent. It already supports chapter/step cards, narration controls, transcript panel, image placeholder renderer, challenge/debrief flow, completion event, reviewer source IDs, and mobile layout. Integration should feed Module 10-only source-traced data rather than replacing the shell.\n',encoding='utf-8')
(OUT/'reports/app_integration_notes.md').write_text('# App Integration Notes\n\nIntegrated Module 10 by replacing clean placeholder data with source-first generated `module10.content.generated.json` and `contentV2.generated.ts` adapter export. Preserved existing LessonPlayer shell. No deployment settings changed.\n',encoding='utf-8')
print('generated module10 artifacts', datetime.now().isoformat())
